#include<bits/stdc++.h>
using namespace std;
#define ll long long
const int N=8000005,inf=0x3f3f3f3f;
int n,m,v,tr[N],a[N],b[N],ans1,ans2;
void pushup(int id)
{
	tr[id]=max(tr[id*2],tr[id*2+1]);
}
void build(int id,int l,int r)
{
	if(l==r) tr[id]=a[l];
	else
	{
		int mid=(l+r)/2;
		build(id*2,l,mid);
		build(id*2+1,mid+1,r);
		pushup(id);
	}
}
int query(int id,int l,int r,int x,int y)
{
	if(l>y||r<x) return -inf;
	if(l>=x&&r<=y)
	{
		return tr[id];
	}
	int mid=(l+r)/2;
	return max(query(id*2,l,mid,x,y),query(id*2+1,mid+1,r,x,y));
}
int main()
{	
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
	cin>>n>>m>>v;
	for(int i=1;i<=n;i++)
	{
		cin>>a[i];
		b[i]=a[i];
		a[i]+=(v*(n-i));
	}
	build(1,1,n);
	while(m--)
	{
		int x,k;
		cin>>x>>k;
		if(k==0||(x+k-1)>n)
		{
			continue;
		}
		int tmp1=query(1,1,n,1,x-1);
		int tmp2=query(1,1,n,x+1,(x+k-1));
		int mx=max(tmp1,tmp2);
		int mn;
		if(tmp1==mx) mn=b[x]-(a[x]-mx);
		else mn=b[x]-(a[x]-mx-1);
		if(mn<0) mn=0;
		ans2+=mn;
		ans1^=mn;
	}
	cout<<ans1<<" "<<ans2;
	return 0;
}
